oldWay:
/* Hex requires manual tuning to match perceived brightness */
.red   { color: #ef4444; } /* lightness ~53% */
.green { color: #22c55e; } /* lightness ~47% — already noticeably different */
.blue  { color: #3b82f6; } /* lightness ~60% — brighter again */
/* Consistent tonal palettes require trial-and-error or a tool */

modernWay:
/* Change only H — L and C stay the same */
.red   { color: oklch(65% 0.22 30); }
.green { color: oklch(65% 0.22 145); }
.blue  { color: oklch(65% 0.22 260); }

startingCSS:
.palette {
  display: flex;
  gap: 1rem;
  justify-content: center;
  padding: 2rem 1.5rem 1.5rem;
  background: #0f172a;
  border-radius: 12px;
}

.swatch {
  width: 110px;
  height: 110px;
  border-radius: 12px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: 700;
  gap: 0.25rem;
}

.swatch span { font-size: 1.1rem; }

.swatch small {
  font-size: 0.6rem;
  opacity: 0.8;
  text-align: center;
  padding: 0 0.25rem;
  font-weight: 400;
  line-height: 1.3;
}

.s1 { background: oklch(65% 0.2 30); }

.s2 {
  background: #475569;
  /* Replace with oklch(65% 0.2 145) */
}

.s3 { background: oklch(65% 0.2 260); }

.note {
  text-align: center;
  color: #64748b;
  font-size: 0.75rem;
  margin: 0.75rem 0 0;
  font-style: italic;
}
